def validate_cart_items(cart_items: List[CartItem]) -> Dict[str, Any]:
    if not cart_items:
        raise CartValidationError("Cart is empty.")

    validated_items: List[Dict[str, Any]] = []
    subtotal = Decimal("0.00")
    taxable_subtotal = Decimal("0.00")

    for item in cart_items:
        if item.quantity <= 0:
            raise CartValidationError(f"Invalid quantity for product {item.product_id}.")
        if not item.active:
            raise CartValidationError(f"Product {item.product_id} is inactive.")
        if item.stock < item.quantity:
            raise CartValidationError(f"Insufficient stock for product {item.product_id}.")
        if item.unit_price < 0:
            raise CartValidationError(f"Invalid price for product {item.product_id}.")

        line_total = money(item.unit_price * item.quantity)
        subtotal += line_total
        if item.taxable:
            taxable_subtotal += line_total

        validated_items.append(
            {
                "product_id": item.product_id,
                "name": item.name,
                "quantity": item.quantity,
                "unit_price": item.unit_price,
                "line_total": line_total,
                "taxable": item.taxable,
            }
        )

    return {
        "items": validated_items,
        "subtotal": money(subtotal),
        "taxable_subtotal": money(taxable_subtotal),
    }


def apply_discount_codes(
    user: User,
    validated_cart: Dict[str, Any],
    discount_codes: List[str],
    available_discounts: Dict[str, DiscountCode],
) -> Dict[str, Any]:
    subtotal: Decimal = validated_cart["subtotal"]
    taxable_subtotal: Decimal = validated_cart["taxable_subtotal"]
    items = validated_cart["items"]

    total_discount = Decimal("0.00")
    taxable_discount = Decimal("0.00")
    applied_codes: List[str] = []

    if not discount_codes:
        return {
            **validated_cart,
            "discount_total": money(total_discount),
            "taxable_discount": money(taxable_discount),
            "subtotal_after_discount": money(subtotal),
            "taxable_subtotal_after_discount": money(taxable_subtotal),
            "applied_codes": applied_codes,
        }

    taxable_ratio = Decimal("0.00")
    if subtotal > 0:
        taxable_ratio = taxable_subtotal / subtotal

    running_subtotal = subtotal

    for raw_code in discount_codes:
        code = raw_code.strip().upper()
        if code not in available_discounts:
            raise DiscountValidationError(f"Discount code {code} does not exist.")

        discount = available_discounts[code]

        if not discount.active:
            raise DiscountValidationError(f"Discount code {code} is inactive.")

        if discount.admin_only and not user.is_admin:
            raise DiscountPermissionError(f"Discount code {code} is admin-only.")

        if discount.allowed_tiers is not None and user.tier not in discount.allowed_tiers:
            raise DiscountPermissionError(
                f"User tier '{user.tier}' is not allowed to use discount code {code}."
            )

        if running_subtotal < discount.min_subtotal:
            raise DiscountValidationError(
                f"Discount code {code} requires minimum subtotal of {discount.min_subtotal}."
            )

        if discount.discount_type == "percent":
            code_discount = money(running_subtotal * (discount.value / Decimal("100")))
        elif discount.discount_type == "fixed":
            code_discount = min(money(discount.value), money(running_subtotal))
        else:
            raise DiscountValidationError(f"Unsupported discount type for code {code}.")

        total_discount += code_discount
        taxable_discount += money(code_discount * taxable_ratio)
        running_subtotal = max(Decimal("0.00"), money(running_subtotal - code_discount))
        applied_codes.append(code)

    subtotal_after_discount = max(Decimal("0.00"), money(subtotal - total_discount))
    taxable_subtotal_after_discount = max(
        Decimal("0.00"), money(taxable_subtotal - taxable_discount)
    )

    return {
        "items": items,
        "subtotal": money(subtotal),
        "taxable_subtotal": money(taxable_subtotal),
        "discount_total": money(total_discount),
        "taxable_discount": money(taxable_discount),
        "subtotal_after_discount": money(subtotal_after_discount),
        "taxable_subtotal_after_discount": money(taxable_subtotal_after_discount),
        "applied_codes": applied_codes,
    }


def calculate_tax(discounted_cart: Dict[str, Any], tax_rate: Decimal | int | float | str) -> Dict[str, Any]:
    tax_rate_decimal = Decimal(str(tax_rate))
    if tax_rate_decimal < 0:
        raise CheckoutError("Tax rate cannot be negative.")

    tax_base: Decimal = discounted_cart["taxable_subtotal_after_discount"]
    tax_total = money(tax_base * tax_rate_decimal)

    return {
        **discounted_cart,
        "tax_rate": tax_rate_decimal,
        "tax_total": tax_total,
        "total": money(discounted_cart["subtotal_after_discount"] + tax_total),
    }


def process_payment(
    payment_info: Dict[str, Any],
    amount: Decimal,
) -> PaymentResult:
    required_fields = {"method", "source"}
    if not required_fields.issubset(payment_info):
        missing = required_fields - set(payment_info.keys())
        raise PaymentProcessingError(f"Missing payment fields: {', '.join(sorted(missing))}")

    if amount <= 0:
        raise PaymentProcessingError("Payment amount must be greater than zero.")

    if payment_info.get("simulate_failure"):
        raise PaymentProcessingError("Payment gateway declined the transaction.")

    return PaymentResult(
        success=True,
        transaction_id=str(uuid4()),
        message="Payment processed successfully.",
    )


def create_order_record(
    user: User,
    taxed_cart: Dict[str, Any],
    payment_result: PaymentResult,
    order_store: InMemoryOrderStore,
    metadata: Optional[Dict[str, Any]] = None,
) -> OrderRecord:
    if not payment_result.success or not payment_result.transaction_id:
        raise CheckoutError("Cannot create order without successful payment.")

    order = OrderRecord(
        order_id=str(uuid4()),
        user_id=user.user_id,
        items=taxed_cart["items"],
        subtotal=money(taxed_cart["subtotal"]),
        discount_total=money(taxed_cart["discount_total"]),
        taxable_subtotal=money(taxed_cart["taxable_subtotal_after_discount"]),
        tax_total=money(taxed_cart["tax_total"]),
        total=money(taxed_cart["total"]),
        applied_codes=list(taxed_cart["applied_codes"]),
        payment_transaction_id=payment_result.transaction_id,
        created_at=datetime.utcnow().isoformat() + "Z",
        metadata=metadata or {},
    )
    return order_store.create(order)


def checkout(
    user: User,
    cart_items: List[CartItem],
    discount_codes: List[str],
    available_discounts: Dict[str, DiscountCode],
    tax_rate: Decimal | int | float | str,
    payment_info: Dict[str, Any],
    order_store: InMemoryOrderStore,
    metadata: Optional[Dict[str, Any]] = None,
) -> OrderRecord:
    validated_cart = validate_cart_items(cart_items)
    discounted_cart = apply_discount_codes(user, validated_cart, discount_codes, available_discounts)
    taxed_cart = calculate_tax(discounted_cart, tax_rate)
    payment_result = process_payment(payment_info, taxed_cart["total"])
    order = create_order_record(user, taxed_cart, payment_result, order_store, metadata)
    return order


